  {
    int minIndex = j;
    for (int k = j + 1; k < arr.length; k++)
    {
      if (arr[k] < arr[minIndex])
      {
        minIndex = k;
      }
    }
    int temp = arr[j];
    arr[j] = arr[minIndex];
    arr[minIndex] = temp;
